 1	import React, { FC, useEffect, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { useLocation } from 'react-router-dom-v5-compat';
 4	
 5	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 8	import { NavPageComponentProps } from '@virtualmachines/details/utils/types';
 9	
10	import useDiagnosticData from './hooks/useDianosticData';
11	import VirtualMachineDiagnosticTabConditions from './tables/VirtualMachineDiagnosticTabConditions';
12	import VirtualMachineDiagnosticTabDataVolumeStatus from './tables/VirtualMachineDiagnosticTabDataVolumeStatus';
13	import VirtualMachineDiagnosticTabVolumeStatus from './tables/VirtualMachineDiagnosticTabVolumeStatus';
14	import { createURLDiagnostic } from './utils/utils';
15	import VirtualMachineLogViewer from './VirtualMachineLogViewer/VirtualMachineLogViewer';
16	
17	import './virtual-machine-diagnostic-tab.scss';
18	
19	const VirtualMachineDiagnosticTab: FC<NavPageComponentProps> = ({ obj: vm }) => {
20	  const navigate = useNavigate();
21	  const location = useLocation();
22	  const { t } = useKubevirtTranslation();
23	  const { conditions, dataVolumesStatuses, volumeSnapshotStatuses } = useDiagnosticData(vm);
24	  const [activeTabKey, setActiveTabKey] = useState<string>();
25	
26	  useEffect(() => {
27	    setActiveTabKey(
28	      location?.pathname?.endsWith(VirtualMachineDetailsTab.Logs)
29	        ? VirtualMachineDetailsTab.Logs
30	        : VirtualMachineDetailsTab.Tables,
31	    );
32	  }, [location.pathname]);
33	
34	  return (
35	    <div className="VirtualMachineDiagnosticTab--main">
36	      <Tabs
37	        onSelect={(_, key: string) => {
38	          navigate(createURLDiagnostic(location.pathname, key));
39	          setActiveTabKey(key);
40	        }}
41	        activeKey={activeTabKey}
42	        className="VirtualMachineDiagnosticTab--main__tabs"
43	        isVertical
44	      >
45	        <Tab
46	          className="VirtualMachineDiagnosticTab--main__content"
47	          data-test-id="vm-diagnostics-status-conditions"
48	          eventKey={VirtualMachineDetailsTab.Tables}
49	          title={<TabTitleText>{t('Status & Conditions')}</TabTitleText>}
50	        >
51	          <VirtualMachineDiagnosticTabConditions conditions={conditions} />
52	          <VirtualMachineDiagnosticTabVolumeStatus
53	            volumeSnapshotStatuses={volumeSnapshotStatuses}
54	          />
55	          <VirtualMachineDiagnosticTabDataVolumeStatus dataVolumesStatuses={dataVolumesStatuses} />
56	        </Tab>
57	        <Tab
58	          className="VirtualMachineDiagnosticTab--main__content"
59	          data-test-id="vm-diagnostics-guest-system-log"
60	          eventKey={VirtualMachineDetailsTab.Logs}
61	          title={<TabTitleText>{t('Guest system log')}</TabTitleText>}
62	        >
63	          <VirtualMachineLogViewer
64	            connect={activeTabKey === VirtualMachineDetailsTab.Logs}
65	            vm={vm}
66	          />
67	        </Tab>
68	      </Tabs>
69	    </div>
70	  );
71	};
72	
73	export default VirtualMachineDiagnosticTab;

